import{_ as d,r as s,o as r,c as o,a as e,b as i,d as n,e as l}from"./app-7b6a7290.js";const u={},h={id:"学习harness编程",tabindex:"-1"},c={href:"https://walkinglabs.github.io/learn-harness-engineering",target:"_blank",rel:"noopener noreferrer"},p={id:"harness不是目的-知识才是护城河",tabindex:"-1"},g={href:"https://mp.weixin.qq.com/s/JV4-oPP0jjsBCZ4tW3Gy1g",target:"_blank",rel:"noopener noreferrer"};function v(b,t){const a=s("ExternalLinkIcon");return r(),o("div",null,[t[6]||(t[6]=e("h1",{id:"harness",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#harness","aria-hidden":"true"},"#"),i(" Harness")],-1)),e("h2",h,[t[1]||(t[1]=e("a",{class:"header-anchor",href:"#学习harness编程","aria-hidden":"true"},"#",-1)),t[2]||(t[2]=i()),e("a",c,[t[0]||(t[0]=i("学习harness编程",-1)),n(a)])]),t[7]||(t[7]=l('<h3 id="模型强-不等于可靠" tabindex="-1"><a class="header-anchor" href="#模型强-不等于可靠" aria-hidden="true">#</a> 模型强，不等于可靠</h3><ul><li>模型能力和执行可靠性是两回事，千里马也得配上好马具。</li><li>失败的时候先看 harness，再看模型。换模型是成本最高的选择，而且很多时候根本不是模型的问题。</li><li>每次失败都是一个信号：你的 harness 有结构性缺陷。把它找出来、修掉。</li><li>遇到失败不要笼统地说&quot;模型不行&quot;。任务没交代清楚、上下文不够、环境没配好、验证手段缺失、上一个会话做到哪了新会话接不上，五个地方逐个排查，问题十有八九出在其中一层。</li><li>一个 AGENTS.md 文件可能比你换一个更贵的模型更有效。</li></ul><div class="hint-container tip"><p class="hint-container-title">提示</p><p>harness做的是在我们这儿可信地干活</p></div><h3 id="harness的定义" tabindex="-1"><a class="header-anchor" href="#harness的定义" aria-hidden="true">#</a> Harness的定义</h3><ul><li>什么是 harness：模型权重之外的一切工程基础设施。OpenAI 把工程师的核心工作概括为三件事：设计环境、表达意图、构建反馈循环。Anthropic 直接把 Claude Agent SDK 称为&quot;通用 agent harness&quot;。五个子系统：指令 + 工具 + 环境 + 状态 + 反馈。反馈是低投入高回报。</li><li>仓库是唯一事实来源：agent 看不到的东西，对它来说就不存在。OpenAI 把仓库当作&quot;记录系统&quot;，所有必要的上下文都必须在仓库里，通过结构化的文件和清晰的目录组织来呈现。</li><li>给地图，不给说明书：OpenAI 的经验是 AGENTS.md 应该是目录页，不是百科全书。100 行左右就够了，放不下就拆分到 docs/ 目录里，让 agent 按需去读。</li><li>约束而非微操：好的 harness 用可执行的规则来约束 agent，而不是在指令里逐条叮嘱。OpenAI 说&quot;执行不变量，不要微管实现&quot;；Anthropic 发现 agent 会自信地夸赞自己的工作，解决方案是把&quot;干活的人&quot;和&quot;检查的人&quot;分开。</li><li>逐个移除看效果：想量化 harness 各组件的边际贡献，就逐个移除，看哪个移除后性能下降最多。它能告诉你哪些组件当前最有价值，也能暴露哪些组件暂时贡献不明显。Anthropic 用这个方法发现：随着模型变强，某些组件不再关键，但总会有新的关键组件出现。</li></ul><h3 id="让代码仓库成为唯一的事实来源" tabindex="-1"><a class="header-anchor" href="#让代码仓库成为唯一的事实来源" aria-hidden="true">#</a> 让代码仓库成为唯一的事实来源</h3><ul><li>知识可见性缺口：项目总知识中不在仓库里的比例。缺口越大，agent 失败的概率越高。你可以这样估算：把脑子里关于这个项目的隐性知识全算上，再看有多少写进了仓库，两者的差距就是可见性缺口。</li><li>系统记录（System of Record）：代码仓库作为项目决策、架构约束、执行状态和验证标准的权威信息源。仓库说了算，别的地方说了不算。如果&quot;此路不通&quot;这个信息只在老张的脑子里，那每次都得问老张。写进仓库，谁都不用问。</li><li>全新会话测试：上一节说的五个问题。能回答几个，你的地图就画了几分。</li><li>发现成本：agent 为了在仓库里找到一条关键信息需要消耗多少上下文。信息放得越隐蔽，发现成本越高，留给实际任务的预算越少。关键信息应该放在 agent 最先看到的位置，而不是藏在十层目录深处。</li><li>知识衰减率：仓库中单位时间内变得过时的知识条目比例。文档和代码脱节是最大的敌人，比没有文档更危险的是过时的文档。</li><li>ACID 类比：把数据库的事务管理原则（原子性、一致性、隔离性、持久性）用到 agent 的状态管理上。后面会展开讲。</li></ul><h3 id="把指令拆分到不同文件里" tabindex="-1"><a class="header-anchor" href="#把指令拆分到不同文件里" aria-hidden="true">#</a> 把指令拆分到不同文件里</h3><ul><li>&quot;加条规则&quot;是短期的止痛药，长期的毒药。每次加规则前想想，这条规则放专题文档是不是更合适。</li><li>入口文件是路由器，不是百科全书。50-200 行，只放概览、硬约束和链接。</li><li>利用&quot;中间迷失&quot;效应：重要信息放文件顶部或底部，不重要的移到专题文档。</li><li>像管理技术债一样管理指令膨胀。定期审计，每条指令要有来源、适用条件和过期条件。</li><li>拆分之后信噪比提升，agent 把更多上下文预算花在实际任务上，而不是处理无关指令。</li></ul><h3 id="让跨会话的任务保持上下文连续" tabindex="-1"><a class="header-anchor" href="#让跨会话的任务保持上下文连续" aria-hidden="true">#</a> 让跨会话的任务保持上下文连续</h3><ul><li>上下文窗口是有限的资源。长任务一定会跨会话，跨会话一定会丢信息，这是客观现实。</li><li>解决方案不是更大的窗口，而是更好的状态持久化。进度文件、决策日志、git 检查点，三者配合让新会话能接上之前的工作。</li><li>把 agent 当成每次会话都会清空短期记忆的工程师来管理：每次&quot;下班&quot;前写清楚做了什么、为什么、下一步做什么。</li><li>重建成本是关键指标。好的 harness 应该让新会话在 3 分钟内恢复到可执行状态。</li><li>混合策略：短任务在会话内完成，长任务用结构化工件维持连续性。</li></ul><h3 id="让-agent-每次工作前先初始化" tabindex="-1"><a class="header-anchor" href="#让-agent-每次工作前先初始化" aria-hidden="true">#</a> 让 agent 每次工作前先初始化</h3><ul><li>初始化阶段：agent 生命周期中的第一个阶段，只建立后续实现所需的执行前提，不做功能开发。它的产出是基础设施，而不是业务代码。</li><li>启动就绪清单：一个项目能被全新 agent 会话无歧义操作的条件：能启动、能测试、能看进度、能接手下一步。四个条件缺一不可。</li><li>从零开始 vs 从模板开始：从零开始意味着 agent 需要自行推断项目结构，效果差；从模板开始意味着基础设施已经就位，效果好得多。能用模板就用模板。</li><li>随时可接手：项目在任何时刻都处于&quot;可以被全新 agent 接手&quot;的状态。不需要口头解释，只看仓库内容就能接着干。</li><li>从开始到第一次测试通过：衡量初始化效率的核心指标。时间越短，初始化越高效。</li><li>后续会话的成功率：后续会话不需要依赖隐式知识就能成功执行任务的比例，这是初始化质量的最佳衡量标准。</li></ul><h3 id="给-agent-划清每次任务的边界" tabindex="-1"><a class="header-anchor" href="#给-agent-划清每次任务的边界" aria-hidden="true">#</a> 给 agent 划清每次任务的边界</h3><ul><li>WIP=1 是 agent harness 的默认安全设置：做完一个再做下一个，不要试图并行。</li><li>完成证据必须是可执行的：&quot;代码看起来没问题&quot;不算完成，&quot;curl 返回 201&quot;才算。</li><li>范围表面必须外部化为文件：不能只在对话里说，必须在仓库里有机器可读的记录。</li><li>overreach 和 under-finish 是共生问题：解决一个就解决了另一个。</li><li>&quot;少做但做完&quot;永远优于&quot;多做但做半&quot;：agent 代码行数和功能完成率呈负相关，质量永远比数量重要。</li></ul><h3 id="用功能清单约束-agent-该做什么" tabindex="-1"><a class="header-anchor" href="#用功能清单约束-agent-该做什么" aria-hidden="true">#</a> 用功能清单约束 agent 该做什么</h3><ul><li>功能清单是 harness 的基础结构，不是给人看的备忘录。调度器、验证器、交接器都依赖它。</li><li>每个功能项必须有三元组：行为描述 + 验证命令 + 当前状态。缺一项就不完整。</li><li>状态转移由 harness 控制，agent 不能自己改状态。通过验证是唯一的升级路径。</li><li>功能清单是项目的单一权威来源，任何关于&quot;该做什么&quot;的信息都从这里派生。</li><li>粒度控制在&quot;一次会话能完成&quot;的范围。太粗做不完，太细管不过来。</li></ul><h3 id="防止-agent-提前宣告完成" tabindex="-1"><a class="header-anchor" href="#防止-agent-提前宣告完成" aria-hidden="true">#</a> 防止 agent 提前宣告完成</h3><ul><li>agent 系统性地过度自信，置信度校准偏差是客观存在的。代码写完了不代表做对了。</li><li>完成判定必须外部化，harness 独立验证，不信任 agent 的&quot;感觉&quot;。</li><li>三层校验缺一不可：语法通过、行为通过、系统通过，层层递进。</li><li>错误消息要包含具体修复步骤，让 agent 能自我修正，只说&quot;错了&quot;不够。</li><li>核心功能验证通过之前不许重构，完成优先级约束是防止过早优化的关键。</li></ul><h3 id="跑通完整流程才算真正验证" tabindex="-1"><a class="header-anchor" href="#跑通完整流程才算真正验证" aria-hidden="true">#</a> 跑通完整流程才算真正验证</h3><ul><li>单元测试对组件边界缺陷系统性盲视：它们的隔离设计恰好使其无法检测交互问题。</li><li>端到端测试不仅检测缺陷，还改变 agent 的编码行为：让它更关注集成和边界。</li><li>架构规则必须可执行：每次提交自动检查，不能只写在文档里等人来看。</li><li>错误消息要面向 agent 设计：包含&quot;怎么修&quot;的具体步骤，形成自我修正闭环。</li><li>审查反馈提升让 harness 自动变强：每个被捕获的缺陷类别都变成永久防线。</li></ul><h3 id="让-agent-的运行过程可观测" tabindex="-1"><a class="header-anchor" href="#让-agent-的运行过程可观测" aria-hidden="true">#</a> 让 agent 的运行过程可观测</h3><ul><li>运行时可观测性：系统层的信号，包括日志、追踪、进程事件、健康检查，回答&quot;系统做了什么&quot;。</li><li>过程可观测性：harness 决策工件的可见性，包括计划、评分标准、验收条件，回答&quot;为什么这个变更应该被接受&quot;。</li><li>任务轨迹：一个任务从开始到完成的完整决策路径记录，类似分布式系统中的请求追踪。agent 的每一步操作及其上下文都被记录，出了问题可以回放完整过程。</li><li>冲刺合同：编码开始前协商的短期协议，明确任务范围、验证标准、排除项。是过程可观测性的核心工具。</li><li>评估评分标准：把质量评估从主观判断变成基于证据的结构化评分，使不同评估者对同一输出产生相似结论。</li><li>双层可观测性：系统层和过程层同时设计、相互增强。运行时信号解释行为，过程工件解释意图。</li></ul><h3 id="每次会话结束前都做好交接" tabindex="-1"><a class="header-anchor" href="#每次会话结束前都做好交接" aria-hidden="true">#</a> 每次会话结束前都做好交接</h3><ul><li>清洁状态是会话完成的必要条件。它是&quot;完成&quot;定义的一部分，属于必要条件。代码写完了但状态是脏的，那就不算做完。</li><li>五个维度缺一不可：构建、测试、进度、工件、启动。每一条都要在退出时显式检查，不能靠&quot;感觉应该没问题&quot;。</li><li>功能清单让 agent 知道&quot;做完&quot;的标准。没有清单，agent 用自己的标准判断完成，那个标准几乎一定比你的标准低。</li><li>质量文档让代码库的健康状况可追踪。知道哪里在退化，才能主动修复。不知道问题在哪儿，就只能等它爆发。</li><li>定期简化 Harness：随着模型能力提升，主动移除不再必要的组件。今天必须有的约束，三个月后可能就是累赘。</li><li>&quot;以后再清理&quot;等于永远不清理。熵增是默认方向，只有主动的清洁操作才能对抗它。每次多花五分钟，长期来看是回报最高的投资</li></ul>',25)),e("h2",p,[t[4]||(t[4]=e("a",{class:"header-anchor",href:"#harness不是目的-知识才是护城河","aria-hidden":"true"},"#",-1)),t[5]||(t[5]=i()),e("a",g,[t[3]||(t[3]=i("Harness不是目的，知识才是护城河",-1)),n(a)])]),t[8]||(t[8]=l(`<p>工作流只是管道，知识才是流过管道的活水。</p><blockquote><p>&quot;将来的技术护城河不在模型，而在垂直领域知识的沉淀。&quot;</p></blockquote><p>模型会迭代，工具链会更新，工作流会重构。但你的团队在一个特定业务领域积累的领域模型、架构决策、最佳实践、已知陷阱、业务流程——这些知识是永恒的，是不会因为模型换代而失效的。</p><blockquote><p>Skill、Agent、工具链会随模型迭代更新，但领域知识是永恒的。</p></blockquote><h3 id="知识分层" tabindex="-1"><a class="header-anchor" href="#知识分层" aria-hidden="true">#</a> 知识分层</h3><h4 id="知识体系的三个维度" tabindex="-1"><a class="header-anchor" href="#知识体系的三个维度" aria-hidden="true">#</a> 知识体系的三个维度</h4><table><thead><tr><th>维度</th><th style="text-align:left;">回答的问题</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td>存储层（在哪）</td><td style="text-align:left;">知识存在哪里？</td><td style="text-align:left;">Layer 0-P 0-T 1 2 3 — 从个人到团队到项目</td></tr><tr><td>知识类型（是什么）</td><td style="text-align:left;">知识描述的是什么？</td><td style="text-align:left;">model decision guideline pitfall process</td></tr><tr><td>成熟度（多可信）</td><td style="text-align:left;">知识经过多少验证？</td><td style="text-align:left;">draft → verified → proven</td></tr></tbody></table><h4 id="五层存储架构" tabindex="-1"><a class="header-anchor" href="#五层存储架构" aria-hidden="true">#</a> 五层存储架构</h4><ul><li>Layer 0-P（个人偏好）：你喜欢 4 空格缩进还是 2 空格？偏好函数式还是面向对象？这是纯个人的，不应该强制给团队。</li><li>Layer 0-T（团队约定）：代码规范、Commit 规范、Review 标准。这是团队层面的&quot;宪法&quot;，相对稳定。</li><li>Layer 1（技术知识）：跨项目通用的技术经验。比如&quot;Spring Boot 多租户拦截器设计模式&quot;、&quot;Optional 依赖传递陷阱&quot;。</li><li>Layer 2（业务知识）：特定业务领域的领域模型、业务规则、业务流程。比如&quot;广告审核流程：提交→机审→人审→上线&quot;。</li><li>Layer 3（项目知识）：仅在当前项目有意义的上下文。比如&quot;本项目数据库用的是 TencentDB for MySQL 8.0&quot;。</li></ul><p><strong>关键设计：知识可以&quot;向上提升&quot;。</strong> Layer 3 的项目知识，如果被判定为跨项目通用，会自动提升到 Layer 1 或 Layer 2。</p><h4 id="五种技术类型" tabindex="-1"><a class="header-anchor" href="#五种技术类型" aria-hidden="true">#</a> 五种技术类型</h4><p>知识按&quot;描述的是什么&quot;分类，遵循 MECE（互斥且完全穷尽）原则：</p><table><thead><tr><th>类型</th><th style="text-align:left;">定义</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td>model</td><td style="text-align:left;">实体定义、数据结构、关系图</td><td style="text-align:left;">&quot;广告计划包含预算/出价/投放时段三个核心字段&quot;</td></tr><tr><td>decision</td><td style="text-align:left;">技术选型、架构决策及理由</td><td style="text-align:left;">&quot;选择事件驱动而非 RPC 同步，因为广告状态变更需要解耦&quot;</td></tr><tr><td>guideline</td><td style="text-align:left;">推荐做法 (recommend) 或禁止做法 (avoid)</td><td style="text-align:left;">recommend: &quot;公共模块变更后的兼容性检查清单&quot;</td></tr><tr><td>pitfall</td><td style="text-align:left;">已知风险、故障模式、排查步骤</td><td style="text-align:left;">&quot;广告预算扣减在高并发下会超扣&quot;</td></tr><tr><td>process</td><td style="text-align:left;">业务流程、状态机、操作步骤</td><td style="text-align:left;">&quot;广告审核：提交→机审→人审→上线&quot;</td></tr></tbody></table><p>这五种类型覆盖了我们在实践中遇到的所有知识形态。每一条知识只属于一个类型，来源信息记录在元数据中用于溯源分析。</p><h4 id="三级成熟度-自动衰减" tabindex="-1"><a class="header-anchor" href="#三级成熟度-自动衰减" aria-hidden="true">#</a> 三级成熟度 + 自动衰减</h4><p>知识不是&quot;写完就完了&quot;。它有生命周期。</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>draft（新提取，单一来源）
  ↓ 在 1 个工作流中被成功引用
verified（单项目验证）
  ↓ 在 ≥2 个不同项目中被验证
proven（成熟/可信赖）
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>更关键的是自动衰减机制——知识如果长期不被引用，会自动降级：</p><table><thead><tr><th>触发条件</th><th style="text-align:left;">衰减动作</th></tr></thead><tbody><tr><td>proven 条目 12 个月未被引用</td><td style="text-align:left;">降级为 verified</td></tr><tr><td>verified 条目 6 个月未被引用</td><td style="text-align:left;">降级为 draft</td></tr><tr><td>draft 条目持续未引用 + Lint 标记</td><td style="text-align:left;">归档，移出活跃索引</td></tr></tbody></table><p>为什么需要衰减？ 因为知识也会过时。一条三年前的&quot;最佳实践&quot;，可能因为框架版本升级已经不再适用。与其让过时知识误导 Agent，不如让它自然衰减退出活跃库。</p><p>这个设计借鉴了 Karpathy 在 LLM Wiki 概念中提出的 Lint 操作——定期识别矛盾、孤儿页、缺失交叉引用和数据缺口。</p><h3 id="单一知识库" tabindex="-1"><a class="header-anchor" href="#单一知识库" aria-hidden="true">#</a> 单一知识库</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>team-knowledge.git                        ← 独立 Git 仓库
├── knowledge-catalog.md                  ← 全景目录（Agent 查询入口）
├── .knowledge-config.yaml                ← 团队配置（成员、冲突策略）
├── team-conventions/                     ← Layer 0-T: 团队约定
│   ├── coding-standards.md
│   └── commit-conventions.md
├── tech-wiki/                            ← Layer 1: 技术知识
│   ├── catalog.md                        ← 分类清单
│   ├── patterns/TK-PAT-001.md
│   └── anti-patterns/TK-AP-001.md
├── biz-wiki/                             ← Layer 2: 业务知识
│   └── {domain}/
│       ├── catalog.md
│       ├── entities/BK-AD-E001.md
│       └── pitfalls/BK-AD-P001.md
├── project-profiles/                     ← 项目画像
└── contributions/                        ← 贡献暂存区
    ├── pending/
    └── conflicts/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="为什么要独立仓库" tabindex="-1"><a class="header-anchor" href="#为什么要独立仓库" aria-hidden="true">#</a> 为什么要独立仓库？</h4><ul><li>跨项目共享：同一个团队的多个项目连接同一个知识仓库，项目 A 沉淀的知识，项目 B 自动受益。</li><li>生命周期独立：业务项目可能归档或重构，但知识不应该跟着项目消失。</li><li>权限独立：知识库的贡献和消费权限可以独立于代码仓库管理。</li></ul><h4 id="三种团队角色" tabindex="-1"><a class="header-anchor" href="#三种团队角色" aria-hidden="true">#</a> 三种团队角色</h4><table><thead><tr><th>角色</th><th style="text-align:left;">权限</th><th style="text-align:left;">适用人群</th></tr></thead><tbody><tr><td>maintainer</td><td style="text-align:left;">裁决内容冲突、审批 proven 提升、管理成员</td><td style="text-align:left;">团队负责人、资深工程师</td></tr><tr><td>contributor</td><td style="text-align:left;">通过工作流自动贡献（创建/验证/标记矛盾）</td><td style="text-align:left;">正式团队成员</td></tr><tr><td>reader</td><td style="text-align:left;">只消费知识（查询/注入），不贡献</td><td style="text-align:left;">新成员试用期</td></tr></tbody></table><h4 id="贡献模式-——-贡献暂存-异步合并" tabindex="-1"><a class="header-anchor" href="#贡献模式-——-贡献暂存-异步合并" aria-hidden="true">#</a> 贡献模式 —— &quot;贡献暂存 + 异步合并&quot;</h4><table><thead><tr><th>区块链思想</th><th style="text-align:left;">AI Team 实现</th><th style="text-align:left;">机制</th></tr></thead><tbody><tr><td>不可篡改的追加日志</td><td style="text-align:left;">log.md 只追加不修改</td><td style="text-align:left;">每条变更记录贡献者、时间、会话哈希</td></tr><tr><td>贡献可溯源</td><td style="text-align:left;">evidence.contributors[]</td><td style="text-align:left;">类似 Git blame，粒度为知识条目级</td></tr><tr><td>共识机制</td><td style="text-align:left;">maturity 多人验证提升</td><td style="text-align:left;">draft→verified: 1 人验证; verified→proven: ≥2 人 + ≥2 项目</td></tr></tbody></table><p>log.md 示例：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>## [2026-04-09] ingest | [Steven] | 门店履约视图归档 | +1 decision, +2 guideline | #a3f8c2
- 新增 DEC-005: 地图组件选型（腾讯地图 GL JS SDK）
- 新增 GL-012: fitBounds 在 flexbox 布局中的替代方案 (polarity=recommend)

## [2026-04-12] verify | [Alice] | 跨项目验证 | maturity↑ 2 | #c5f0e2
- TK-SB-003 &quot;分页查询延迟关联优化&quot; (verified→proven, 2 projects)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="冲突解决策略" tabindex="-1"><a class="header-anchor" href="#冲突解决策略" aria-hidden="true">#</a> 冲突解决策略</h4><p>当多名成员同时向知识库贡献时，按以下策略自动处理：</p><table><thead><tr><th>冲突类型</th><th style="text-align:left;">处理方式</th></tr></thead><tbody><tr><td>纯新增<br>（不同条目）</td><td style="text-align:left;">自动合并，两条都保留</td></tr><tr><td>证据追加<br>（同条目验证）</td><td style="text-align:left;">自动合并，evidence 数组合并去重</td></tr><tr><td>成熟度提升</td><td style="text-align:left;">自动合并</td></tr><tr><td>内容矛盾</td><td style="text-align:left;">写入 contributions/conflicts/，通知 maintainer 裁决</td></tr><tr><td>成熟度冲突<br>（一升一降）</td><td style="text-align:left;">保留较低成熟度 + 标记 contradiction</td></tr></tbody></table><p>设计理念：大多数情况（纯新增、证据追加、成熟度提升）可以自动处理，只有真正的内容矛盾才需要人工介入。这让知识的共建过程尽可能低摩擦。</p><h3 id="工作流如何服务于知识沉淀" tabindex="-1"><a class="header-anchor" href="#工作流如何服务于知识沉淀" aria-hidden="true">#</a> 工作流如何服务于知识沉淀</h3><h4 id="知识的完整生命周期-三通道沉淀" tabindex="-1"><a class="header-anchor" href="#知识的完整生命周期-三通道沉淀" aria-hidden="true">#</a> 知识的完整生命周期：三通道沉淀</h4><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>/flow-import（一次性冷启动）        /flow-run（每次需求）
      │                                │
      ▼                                ▼
 冷启动导入                       INIT: git pull 知识仓库
3 Agent 管道                          │  + 注入查询入口
 → 知识写入团队仓库                    │
                                       │  ← Agent 在各阶段按需查询
                                       │     （三级渐进式索引）
                                       ▼
                                 ARCHIVE: 知识提取 + 提升判定
                                       │
                                       ├→ Layer 3: docs/knowledge-base/
                                       ├→ Layer 1: tech-wiki/  ← git push
                                       └→ Layer 2: biz-wiki/  ← git push
                                                   │
                                                   ▼
                                            下一个人的 /flow-run 自动受益
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>三个关键时刻：</strong></p><ol><li>INIT 阶段（知识注入）：工作流启动时，自动 git pull 团队知识仓库，将知识全景目录注入 Agent 的查询入口。新启动的工作流自动站在前人肩上。</li><li>各阶段执行中（知识消费）：Agent 在决策点按需查询知识库。比如 @tech-explorer 在技术分析阶段查询&quot;有没有类似的架构决策&quot;，@backend-architect 在架构设计阶段查询&quot;有没有已知的反模式&quot;。</li><li>ARCHIVE 阶段（知识提取）：工作流完成后，@archiver 自动从全流程产物中提取知识条目——架构决策变成 decision，踩过的坑变成 pitfall，总结的经验变成 guideline。提取后执行提升判定，符合条件的自动提升到 Layer 1 或 Layer 2。</li></ol><h4 id="各阶段查询什么知识" tabindex="-1"><a class="header-anchor" href="#各阶段查询什么知识" aria-hidden="true">#</a> 各阶段查询什么知识</h4><p>每个阶段的 Agent 有独立的查询预算，聚焦不同类型的知识：</p><table><thead><tr><th>阶段</th><th style="text-align:left;">查询焦点</th><th style="text-align:left;">重点知识类型</th></tr></thead><tbody><tr><td>ANALYSE_PRODUCT</td><td style="text-align:left;">业务知识 (Layer 2) + 历史需求</td><td style="text-align:left;">model, process, pitfall</td></tr><tr><td>ANALYSE_TECH</td><td style="text-align:left;">技术知识 (Layer 1) + 归档索引</td><td style="text-align:left;">decision, guideline(avoid), pitfall</td></tr><tr><td>ARCHITECT</td><td style="text-align:left;">架构模式 + 实体关系</td><td style="text-align:left;">decision, model</td></tr><tr><td>IMPLEMENT</td><td style="text-align:left;">编码实践 + 团队约定</td><td style="text-align:left;">guideline, pitfall</td></tr><tr><td>BUILD_VERIFY</td><td style="text-align:left;">反模式库</td><td style="text-align:left;">pitfall, guideline(avoid)</td></tr></tbody></table><p>为什么要限制查询预算？ 因为 Agent 如果无限制地读取知识库，会导致上下文膨胀——这恰恰是 Harness Engineering 要解决的核心问题之一。我们通过预算控制，让知识消费&quot;精准&quot;而非&quot;贪婪&quot;。</p><h4 id="冷启动导入-——-flow-import" tabindex="-1"><a class="header-anchor" href="#冷启动导入-——-flow-import" aria-hidden="true">#</a> 冷启动导入 —— /flow-import</h4><p>对于历史项目（已有大量代码但没有知识库），我们提供了 /flow-import 命令，通过 3 个 Agent 的管道实现冷启动：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>@doc-collector → 多源资料收集
  │              （Git/TAPD/iwiki/本地文档/口述）
  ↓
@codebase-profiler → 代码画像
  │                   （技术栈/模块/依赖/模式，60 次搜索预算）
  ↓
@knowledge-builder → 知识标准化
                      （4 维基线 + ≤13 条知识条目 + 归档总结）
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>所有产出条目初始 maturity 为 draft，后续工作流的执行会逐步验证和提升它们。</p><h3 id="知识的按需消费-三级索引-查询预算" tabindex="-1"><a class="header-anchor" href="#知识的按需消费-三级索引-查询预算" aria-hidden="true">#</a> 知识的按需消费：三级索引 + 查询预算</h3><h4 id="从-推送-到-主动查询-的范式转变" tabindex="-1"><a class="header-anchor" href="#从-推送-到-主动查询-的范式转变" aria-hidden="true">#</a> 从&quot;推送&quot;到&quot;主动查询&quot;的范式转变</h4><p>传统做法是在 Agent 启动时，把一堆知识&quot;推送&quot;给它。这有两个问题：</p><ul><li>信息过载：推送太多知识，Agent 反而被淹没，找不到关键信息。</li><li>不精准：预先推送的知识不一定是 Agent 当前决策点需要的。</li></ul><p>我们的设计理念是：Agent 不被动接收固定数量的知识推荐，而是通过三级渐进式索引主动按需查阅。</p><h4 id="三级渐进式索引" tabindex="-1"><a class="header-anchor" href="#三级渐进式索引" aria-hidden="true">#</a> 三级渐进式索引</h4><table><thead><tr><th>层级</th><th style="text-align:left;">文件</th><th style="text-align:left;">大小</th><th style="text-align:left;">作用</th></tr></thead><tbody><tr><td>Layer A: 全景目录</td><td style="text-align:left;">knowledge-catalog.md</td><td style="text-align:left;">~50 行</td><td style="text-align:left;">&quot;知识库有什么？&quot;——分类统计 + 按阶段推荐查阅路径</td></tr><tr><td>Layer B: 分类清单</td><td style="text-align:left;">各目录下的 catalog.md</td><td style="text-align:left;">~100-300 行</td><td style="text-align:left;">&quot;这个分类有哪些条目？&quot;——每条一行摘要（ID + 标题 + 成熟度 + 标签）</td></tr><tr><td>Layer C: 完整条目</td><td style="text-align:left;">TK-<em>.md / BK-</em>.md</td><td style="text-align:left;">~50-200 行</td><td style="text-align:left;">&quot;这条知识说了什么？&quot;——完整内容 + 背景 + 适用场景</td></tr></tbody></table><p><strong>渐进查询流程：</strong></p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>Step 1: 读全景目录（~50 行，零成本）
  → 了解知识库有什么分类、每类多少条
  → 定位当前阶段推荐查阅的 catalog.md 路径

Step 2: 读分类清单（~100-300 行，低成本）
  → 每条知识一行摘要
  → 按 tags / applicable_phases 过滤相关条目

Step 3: 读完整条目（按需，每条 50-200 行）
  → 获取完整知识内容

Step 4: 读原始产物（深入，可选）
  → 沿 source_references 追溯原始推导过程
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这意味着 Agent 可以用 ~50 行的成本 了解知识库全貌，用 ~300 行的成本 定位到相关条目，只在真正需要时才读取完整内容。对比&quot;一次性推送 50 条完整知识&quot;（可能 5000-10000 行），上下文效率提升了一个数量级。</p><h4 id="知识引用追踪闭环" tabindex="-1"><a class="header-anchor" href="#知识引用追踪闭环" aria-hidden="true">#</a> 知识引用追踪闭环</h4><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code><span class="token punctuation">{</span>
  <span class="token property">&quot;knowledgeReferences&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span>
    <span class="token punctuation">{</span> <span class="token property">&quot;id&quot;</span><span class="token operator">:</span> <span class="token string">&quot;TK-SB-003&quot;</span><span class="token punctuation">,</span> <span class="token property">&quot;title&quot;</span><span class="token operator">:</span> <span class="token string">&quot;分页查询延迟关联优化&quot;</span><span class="token punctuation">,</span> <span class="token property">&quot;usedIn&quot;</span><span class="token operator">:</span> <span class="token string">&quot;复用评级 Step 2&quot;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token punctuation">{</span> <span class="token property">&quot;id&quot;</span><span class="token operator">:</span> <span class="token string">&quot;BK-AD-G004&quot;</span><span class="token punctuation">,</span> <span class="token property">&quot;title&quot;</span><span class="token operator">:</span> <span class="token string">&quot;广告预算扣减并发控制规则&quot;</span><span class="token punctuation">,</span> <span class="token property">&quot;usedIn&quot;</span><span class="token operator">:</span> <span class="token string">&quot;业务规则参考&quot;</span> <span class="token punctuation">}</span>
  <span class="token punctuation">]</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="落地经验与思考" tabindex="-1"><a class="header-anchor" href="#落地经验与思考" aria-hidden="true">#</a> 落地经验与思考</h3><h4 id="历史项目引入-从-0-到-1-的冷启动挑战" tabindex="-1"><a class="header-anchor" href="#历史项目引入-从-0-到-1-的冷启动挑战" aria-hidden="true">#</a> 历史项目引入：从 0 到 1 的冷启动挑战</h4><p>最大的挑战不是设计架构，而是让已有项目的隐性知识显性化。很多团队的知识散落在 Wiki评论、聊天记录、甚至团队成员的脑子里。</p><ol><li>多源收集：/flow-import 支持 Git 仓库扫描、TAPD 需求拉取、iWiki 文档导入、本地文档解析、口述录入等多种输入方式。</li><li>渐进导入：不追求一次性导入完美，所有导入知识初始 maturity 为 draft（置信度 0.5-0.6），通过后续工作流的实际使用逐步验证提升。</li><li>断点恢复：导入过程通过 import-state.json 持久化进度，支持中断后继续。</li></ol><h4 id="知识膨胀治理-lint-机制" tabindex="-1"><a class="header-anchor" href="#知识膨胀治理-lint-机制" aria-hidden="true">#</a> 知识膨胀治理：Lint 机制</h4><p>知识库不能只进不出。我们设计了定期的 Lint 机制（借鉴 Karpathy 的 LLM Wiki）：</p><table><thead><tr><th>检查项</th><th style="text-align:left;">处理方式</th></tr></thead><tbody><tr><td>索引不一致</td><td style="text-align:left;">自动修复</td></tr><tr><td>孤儿条目（无引用、无验证）</td><td style="text-align:left;">降级为 draft</td></tr><tr><td>矛盾检测（同主题相反结论）</td><td style="text-align:left;">标记冲突，等待 maintainer 裁决</td></tr><tr><td>过时检测（6 月未引用的 draft）</td><td style="text-align:left;">自动归档</td></tr><tr><td>重复/相似条目</td><td style="text-align:left;">标记合并候选</td></tr><tr><td>成熟度衰减</td><td style="text-align:left;">按规则自动降级</td></tr></tbody></table><p>Lint 触发方式包括：每完成 10 个工作流自动触发、/knowledge lint 手动触发、连续 30 天未执行时在下次 /flow-run 启动时提醒。</p><h4 id="从-文件即状态-到-知识即资产" tabindex="-1"><a class="header-anchor" href="#从-文件即状态-到-知识即资产" aria-hidden="true">#</a> 从&quot;文件即状态&quot;到&quot;知识即资产&quot;</h4><p>AI Team 的设计哲学中，有一条看似朴素但非常重要的原则：文件系统即状态机。所有的状态、产物、知识都以文件形式存在，没有数据库、没有独立平台。</p><p>这不是技术妥协，而是刻意选择：</p><ul><li>可见性：所有知识都是 Markdown 文件，人可以直接阅读、编辑、审查。</li><li>可版本化：Git 管理的文件天然有版本历史。</li><li>可迁移性：不依赖任何特定平台或服务，换工具链时知识不会丢失。</li><li>IDE 原生：.codebuddy/ 目录驱动，被 IDE 原生识别，零配置成本。</li></ul>`,72))])}const m=d(u,[["render",v],["__file","01Harness.html.vue"]]);export{m as default};
